  ('cpa-moex-01354', 'cpa', 'cpa-moex-103-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員欲蒐集證據來測試管理階層的下列聲明：「租賃設備資產的資本化金額，經適當評價。」在下 列證據中，何者最具說服力？', '["直接觀察租賃設備", "檢視租賃合約，並重新計算資本化的金額和當期攤銷的部分", "向供應商發函詢證類似設備的當期購買價格", "向出租人發函詢證設備的原始成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "11136eb40783", "answer_pdf_sha1": "e8b48647d0fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
